//#region src/define.ts
function method(declaration) {
	return declaration;
}
function defineAdapter(config) {
	const methodDefinitions = config.methods ?? {};
	const operations = {
		"adapter.info": async () => buildAdapterInfo(config, methodDefinitions),
		"adapter.accounts.list": async (ctx) => {
			const definedCtx = await createDefinedContext(config, ctx, ctx.runtime?.connection_id);
			if (config.connection?.accounts) return await config.connection.accounts(definedCtx);
			return defaultAccounts(ctx);
		},
		"adapter.health": async (ctx, args) => {
			const definedCtx = await createDefinedContext(config, ctx, args.connection_id);
			if (config.connection?.health) return {
				...await config.connection.health(definedCtx),
				connection_id: args.connection_id
			};
			return {
				connected: true,
				connection_id: args.connection_id
			};
		},
		methods: buildMethodHandlers(config, methodDefinitions)
	};
	if (config.ingest?.monitor) operations["adapter.monitor.start"] = async (ctx, args, emit) => {
		const definedCtx = await createDefinedContext(config, ctx, args.connection_id);
		await config.ingest.monitor(definedCtx, emit);
	};
	if (config.ingest?.backfill) operations["records.backfill"] = async (ctx, args, emit) => {
		const definedCtx = await createDefinedContext(config, ctx, args.connection_id);
		await config.ingest.backfill(definedCtx, { since: args.since }, emit);
	};
	if (config.delivery?.send) operations["channels.send"] = async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.target.connection_id);
		return await config.delivery.send(definedCtx, req);
	};
	if (config.delivery?.stream) operations["channels.stream"] = config.delivery.stream;
	if (config.setup?.start) operations["adapter.setup.start"] = async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.connection_id);
		return await config.setup.start(definedCtx, req);
	};
	if (config.setup?.submit) operations["adapter.setup.submit"] = async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.connection_id);
		return await config.setup.submit(definedCtx, req);
	};
	if (config.setup?.status) operations["adapter.setup.status"] = async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.connection_id);
		return await config.setup.status(definedCtx, req);
	};
	if (config.setup?.cancel) operations["adapter.setup.cancel"] = async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.connection_id);
		return await config.setup.cancel(definedCtx, req);
	};
	if (config.control) operations["adapter.control.start"] = config.control;
	return { operations };
}
async function createDefinedContext(config, ctx, connectionId) {
	const client = config.client?.create ? await config.client.create({
		ctx,
		connectionId
	}) : void 0;
	return {
		...ctx,
		connectionId,
		client
	};
}
function defaultAccounts(ctx) {
	const connectionId = ctx.runtime?.connection_id?.trim();
	if (!connectionId) return [];
	return [{
		id: connectionId,
		status: "ready",
		...ctx.runtime?.credential?.ref ? { credential_ref: ctx.runtime.credential.ref } : {}
	}];
}
function buildMethodHandlers(config, methods) {
	if (Object.keys(methods).length === 0) return {};
	return Object.fromEntries(Object.entries(methods).map(([name, declaration]) => [name, async (ctx, req) => {
		const definedCtx = await createDefinedContext(config, ctx, req.connection_id);
		return await declaration.handler(definedCtx, req);
	}]));
}
function buildAdapterInfo(config, methods) {
	const operations = [
		"adapter.info",
		"adapter.accounts.list",
		"adapter.health",
		...config.ingest?.monitor ? ["adapter.monitor.start"] : [],
		...config.ingest?.backfill ? ["records.backfill"] : [],
		...config.delivery?.send ? ["channels.send"] : [],
		...config.delivery?.stream ? ["channels.stream"] : [],
		...config.setup?.start ? ["adapter.setup.start"] : [],
		...config.setup?.submit ? ["adapter.setup.submit"] : [],
		...config.setup?.status ? ["adapter.setup.status"] : [],
		...config.setup?.cancel ? ["adapter.setup.cancel"] : [],
		...config.control ? ["adapter.control.start"] : []
	];
	const methodDescriptors = Object.entries(methods).map(([name, declaration]) => buildMethodDescriptor(name, declaration));
	return {
		platform: config.platform,
		name: config.name,
		version: config.version,
		operations,
		methods: methodDescriptors,
		...config.credential_service ? { credential_service: config.credential_service } : {},
		multi_account: config.multi_account ?? false,
		platform_capabilities: config.capabilities,
		...config.auth ? { auth: config.auth } : {},
		...methodDescriptors.length > 0 ? { methodCatalog: config.methodCatalog ?? {
			source: "manifest",
			namespace: config.platform
		} } : config.methodCatalog ? { methodCatalog: config.methodCatalog } : {}
	};
}
function buildMethodDescriptor(name, declaration) {
	return {
		name,
		...declaration.description !== void 0 ? { description: declaration.description } : {},
		...declaration.action ? { action: declaration.action } : {},
		...declaration.params ? { params: declaration.params } : {},
		...declaration.response ? { response: declaration.response } : {},
		surfaces: declaration.surfaces ?? ["ws.control", "http.control"],
		connection_required: declaration.connection_required ?? true,
		mutates_remote: typeof declaration.mutates_remote === "boolean" ? declaration.mutates_remote : declaration.action === "write",
		...declaration.context_hints ? { context_hints: declaration.context_hints } : {}
	};
}

