//#region src/credentials.ts
function readEnv(name) {
	const value = process.env[name]?.trim();
	return value ? value : void 0;
}
function readCredential(ctx, options = {}) {
	const fields = options.fields ?? [];
	for (const field of fields) {
		const value = ctx.runtime?.credential?.fields?.[field]?.trim();
		if (value) return value;
	}
	if (options.allowValue !== false) {
		const runtimeValue = ctx.runtime?.credential?.value?.trim();
		if (runtimeValue) return runtimeValue;
	}
	const envVars = options.env ?? [];
	for (const name of envVars) {
		const value = readEnv(name);
		if (value) return value;
	}
}
function requireCredential(ctx, options = {}) {
	const value = readCredential(ctx, options);
	if (value) return value;
	const label = options.label?.trim() || "credential";
	const sources = [];
	if ((options.fields ?? []).length > 0) sources.push(`runtime credential fields ${JSON.stringify(options.fields)}`);
	if (options.allowValue !== false) sources.push("runtime credential value");
	if ((options.env ?? []).length > 0) sources.push(`environment ${JSON.stringify(options.env)}`);
	const suffix = sources.length > 0 ? ` (looked in ${sources.join(", ")})` : "";
	throw new Error(`missing ${label}${suffix}`);
}

