//#region src/targets.ts
function asNonEmptyString(value) {
	const trimmed = value?.trim();
	return trimmed ? trimmed : void 0;
}
function requireContainerTarget(target) {
	const value = asNonEmptyString(target.channel.container_id);
	if (!value) throw new Error("target.channel.container_id is required");
	return value;
}
function readThreadTarget(target) {
	return asNonEmptyString(target.channel.thread_id);
}
function readReplyToTarget(target) {
	return asNonEmptyString(target.reply_to_id);
}

