//#region src/retry.ts
async function sleepWithSignal(signal, ms) {
	if (ms <= 0 || signal.aborted) return;
	await new Promise((resolve) => {
		const timer = setTimeout(() => {
			signal.removeEventListener("abort", onAbort);
			resolve();
		}, ms);
		const onAbort = () => {
			clearTimeout(timer);
			signal.removeEventListener("abort", onAbort);
			resolve();
		};
		signal.addEventListener("abort", onAbort, { once: true });
	});
}
function parseRetryAfterMs(value) {
	if (typeof value === "number" && Number.isFinite(value) && value >= 0) return Math.trunc(value);
	if (typeof value !== "string") return;
	const trimmed = value.trim();
	if (!trimmed) return;
	const seconds = Number(trimmed);
	if (Number.isFinite(seconds) && seconds >= 0) return Math.trunc(seconds * 1e3);
	const dateMs = Date.parse(trimmed);
	if (Number.isNaN(dateMs)) return;
	return Math.max(0, dateMs - Date.now());
}
async function withRetry(work, options = {}) {
	const attempts = Math.max(1, Math.trunc(options.attempts ?? 3));
	const factor = options.factor && options.factor > 0 ? options.factor : 2;
	const maxDelayMs = Math.max(0, Math.trunc(options.maxDelayMs ?? 3e4));
	let delayMs = Math.max(0, Math.trunc(options.initialDelayMs ?? 1e3));
	let attempt = 0;
	while (true) {
		attempt += 1;
		try {
			return await work();
		} catch (error) {
			if (!(options.shouldRetry ? options.shouldRetry(error, attempt) : attempt < attempts) || attempt >= attempts || options.signal?.aborted) throw error;
			if (options.onRetry) await options.onRetry(error, attempt, delayMs);
			if (options.signal) await sleepWithSignal(options.signal, delayMs);
			else if (delayMs > 0) await new Promise((resolve) => setTimeout(resolve, delayMs));
			delayMs = Math.min(maxDelayMs, Math.max(delayMs, 1) * factor);
		}
	}
}

